        masked_customer = "***"
        if customer_email and isinstance(customer_email, str) and "@" in customer_email:
            try:
                local, domain = customer_email.split("@", 1)
                masked_local = local[0] + "***" + (local[-1] if len(local) > 1 else "")
                masked_customer = f"{masked_local}@{domain}"
            except Exception:
                masked_customer = "***@***"
        logger.debug(
            "process_order data extracted: order_id=%s, num_items=%d, customer_email=%s, payment_method=%s, coupon_code=%s",
            order_id, len(items), masked_customer, payment_method, coupon_code
        )
    except Exception:
        pass

    # Calculate total
    total = 0
    for item in items:
        price = item.get("price", 0)
        qty = item.get("quantity", 1)
        total += price * qty

    try:
        logger.debug("Subtotal calculated: %.2f from %d items", total, len(items))
    except Exception:
        pass

    # Apply coupon
    discount = 0
    if coupon_code:
        try:
            logger.info("Coupon code provided: %s", coupon_code)
