            except Exception:
                pass
        elif coupon_code == "SAVE20":
            discount = total * 0.20
            try:
                logger.info("Applied SAVE20 coupon, discount=%.2f", discount)
            except Exception:
                pass
        elif coupon_code == "FLAT50":
            discount = min(50, total)
            try:
                logger.info("Applied FLAT50 coupon, discount=%.2f", discount)
            except Exception:
                pass
        else:
            try:
                logger.warning("Unknown coupon code '%s' provided, ignoring", coupon_code)
            except Exception:
                pass
            pass  # Unknown coupon, silently ignored

    final_total = total - discount

    try:
        logger.debug("Final total computed: %.2f (original %.2f minus discount %.2f)", final_total, total, discount)
    except Exception:
        pass

    # Payment processing (simulated)
    if payment_method == "credit_card":
        cc_number = order_data.get("cc_number", "")
        if len(cc_number) != 16:
            try:
                logger.error("Invalid credit card number length provided for order %s", order_id)
            except Exception:
                pass
            raise ValueError("Invalid credit card number")
        try:
            last4 = cc_number[-4:] if cc_number else "****"
            logger.info("Selected credit_card payment method for order %s (card ending %s), amount=%.2f", order_id, last4, final_total)
        except Exception:
            pass
        charge_result = _charge_card(cc_number, final_total)
    elif payment_method == "paypal":
        try:
            logger.info("Selected paypal payment method for order %s, amount=%.2f", order_id, final_total)
