            except Exception:
                pass
        except Exception:
            try:
                logger.warning("Failed to send confirmation email for order %s (non-critical error)", order_id)
            except Exception:
                pass
            pass  # Email failure is not critical

    result = {
        "order_id": order_id,
        "status": "completed",
        "total": final_total,
        "discount": discount,
        "items_count": len(items),
    }

    try:
        logger.info("process_order completed for order %s: status=completed, total=%.2f, discount=%.2f, items_count=%d",
            order_id, final_total, discount, len(items))
    except Exception:
        pass

    return result

